import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is lean body mass?", a: "Lean body mass is body weight minus fat mass. It includes muscle, bone, organs, water, and other non-fat tissue." },
  { q: "How do you calculate lean body mass?", a: "You can estimate lean body mass from formulas using height, weight, and gender, or directly from body fat percentage if known." },
  { q: "What is the difference between lean body mass and fat free mass?", a: "They are often used similarly. Fat free mass strictly means all non-fat mass, while lean body mass may include a small amount of essential fat depending on context." },
  { q: "Why is lean body mass important?", a: "Lean mass affects metabolism, strength, mobility, athletic performance, and health risk assessment." },
  { q: "How do you increase lean body mass?", a: "Progressive strength training, enough protein, sufficient calories, sleep, and consistent recovery support lean mass gain." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const lbToKg = (lb: number) => lb * 0.45359237;
const inToCm = (inch: number) => inch * 2.54;
const kgToLb = (kg: number) => kg / 0.45359237;

export default function LeanBodyMassCalculator() {
  const [gender, setGender] = useState("Male");
  const [height, setHeight] = useState(70);
  const [weight, setWeight] = useState(180);
  const [bodyFat, setBodyFat] = useState(18);
  const result = useMemo(() => {
    const kg = lbToKg(weight);
    const cm = inToCm(height);
    const boer = gender === "Male" ? 0.407 * kg + 0.267 * cm - 19.2 : 0.252 * kg + 0.473 * cm - 48.3;
    const james = gender === "Male" ? 1.1 * kg - 128 * Math.pow(kg / cm, 2) : 1.07 * kg - 148 * Math.pow(kg / cm, 2);
    const hume = gender === "Male" ? 0.3281 * kg + 0.33929 * cm - 29.5336 : 0.29569 * kg + 0.41813 * cm - 43.2933;
    const fromFat = kg * (1 - bodyFat / 100);
    const avg = (boer + james + hume + fromFat) / 4;
    return { boer: kgToLb(boer), james: kgToLb(james), hume: kgToLb(hume), fromFat: kgToLb(fromFat), avg: kgToLb(avg), fatMass: weight - kgToLb(avg) };
  }, [gender, height, weight, bodyFat]);
  const rows = [5, 10, 15, 20, 25, 30, 35].map((pct) => [pct, 180 * pct / 100, 180 * (1 - pct / 100), pct < 10 ? "Essential/Athletic" : pct < 20 ? "Athletic/Fit" : pct < 30 ? "Average" : "High", pct >= 30 ? "Higher" : "Varies"]);
  return (
    <>
      <SEOHead title="Free Lean Body Mass Calculator Online - Calculate Your LBM Instantly | CalcHive" description="Free online lean body mass calculator. Calculate your lean body mass and fat mass using multiple formulas for any height, weight and body fat percentage instantly. 100% free, no signup required." canonical="/lean-body-mass-calculator" keywords="free lean body mass calculator, LBM calculator free online, calculate lean body mass free, fat free mass calculator free, body composition calculator free online" category="Health Calculators" breadcrumbName="Free Lean Body Mass Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Lean Body Mass Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate lean body mass and fat mass using Boer, James, Hume, and body fat percentage methods.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (in)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (lb)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Body fat % (optional)</label><input type="number" value={bodyFat} onChange={(e) => setBodyFat(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Average Lean Body Mass</p><p className="text-5xl sm:text-6xl font-black text-white">{result.avg.toFixed(1)} lb</p></div><div className="grid grid-cols-1 sm:grid-cols-4 gap-3 mt-4">{[["Boer", result.boer], ["James", result.james], ["Hume", result.hume], ["Fat mass", result.fatMass]].map(([label, value]) => <div key={String(label)} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="text-lg font-extrabold">{Number(value).toFixed(1)} lb</p></div>)}</div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Lean Body Mass for Free</h2><p className="text-muted-foreground leading-relaxed">This calculator estimates lean mass with multiple formulas and also uses body fat percentage if you provide it, then averages the results.</p><h2 className="text-2xl font-bold">What Is Lean Body Mass and Why Does It Matter</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Lean Body Mass by Body Fat Percentage - 180lb Person</caption><thead className="bg-muted/60"><tr>{["Body Fat %", "Fat Mass", "Lean Body Mass", "Category", "Health Risk"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={String(r[0])}>{r.map((c, i) => <td key={`${r[0]}-${i}`} className="py-2.5 px-3">{typeof c === "number" ? (i === 0 ? `${c}%` : `${c.toFixed(1)} lb`) : c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free LBM and Fat Mass Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/lean-body-mass-calculator" headingLevel="h3" /></main>
    </>
  );
}


